public int active()
{
    int ret = next active();
    if(ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
        FormDataSource      salesAgreement_ds         = any2Object(this) as FormDataSource;
        salesAgreement_ds.object(fieldNum(AgreementLineQuantityCommitment, CommitedQuantity)).mandatory(true);
        salesAgreement_ds.object(fieldNum(AgreementLineQuantityCommitment, PricePerUnit)).mandatory(true);
    }
    return ret;
}

public boolean validateWrite()
{
    boolean ret = next validateWrite();

    if (ret && ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
        FormDataSource      agrLine         = any2Object(this) as FormDataSource;
        formRun             formRun         = agrLine.formRun();

        ret = ETGSalesAgreementMandatoryValidation::validateFormLines(this.formRun());
    }

    return true;
}
